  "title": "बाइनरी ट्री ट्रैवर्सल",
  "group": "डेटा स्ट्रक्चर्स",
  "options": [
    {
      "text": "इन-ऑर्डर, प्री-ऑर्डर, पोस्ट-ऑर्डर"
    },
    {
      "text": "ब्रेड्थ-फर्स्ट, डेप्थ-फर्स्ट, हीपिफाई"
    },
    {
      "text": "सॉर्ट, सर्च, रोटेट"
    },
    {
      "text": "पुश, पॉप, पीक"
    }
  ],
  "questionProse": [
    "बाइनरी ट्री के लिए आमतौर पर इस्तेमाल होने वाले डेप्थ-फर्स्ट ट्रैवर्सल ऑर्डर्स का सही सेट कौन सा है?"
  ],
  "explanationProse": [
    "इन-ऑर्डर, प्री-ऑर्डर और पोस्ट-ऑर्डर बाइनरी ट्री के तीन मुख्य डेप्थ-फर्स्ट ट्रैवर्सल ऑर्डर्स हैं, जिनमें नोड्स को विजिट करने का क्रम अलग-अलग होता है। ब्रेड्थ-फर्स्ट ट्रैवर्सल भी उतना ही कॉमन है, लेकिन यह ट्रैवर्सल की एक बिल्कुल अलग कैटेगरी में आता है।"
  ]
}
